import{_ as o,C as e,o as s,c as d,a2 as r,E as i,j as n}from"./chunks/framework.BnBoz4Zl.js";const l="/anjian-workbuddy-bluebook-site/assets/001_video-work-is-hard_Jn32bhqaho.rwnFXEX8.png",p="/anjian-workbuddy-bluebook-site/assets/002_two-ai-video-teams_SXcUb9mpMo.Cf53uCRv.png",b="/anjian-workbuddy-bluebook-site/assets/003_summon-expert-team-pc_FHrNbNCiBo.C_dD-dni.png",h="/anjian-workbuddy-bluebook-site/assets/004_video-team-roles_ZOJ8b7aQ7o.lfmhenYQ.png",_="/anjian-workbuddy-bluebook-site/assets/005_multi-agent-team-overview_NzPHbTGH2o.BFWkpQ9m.png",u="/anjian-workbuddy-bluebook-site/assets/006_hyperframes-engine_Uj4hbc6Tzo.CYZFNQ_m.png",c="/anjian-workbuddy-bluebook-site/assets/007_collection-report_KPn1bXgYQo.DsCyZHHa.png",m="/anjian-workbuddy-bluebook-site/assets/008_planner-full_YPM3boyNTo.CHx0xrr_.png",E="/anjian-workbuddy-bluebook-site/assets/009_video-producer_PohnbE1jKo.CmEbaTj1.png",g="/anjian-workbuddy-bluebook-site/assets/010_workbuddy-flow_FSJzb5xLQo.dELsALQx.png",A="/anjian-workbuddy-bluebook-site/assets/011_publish-demo_DdTYbbBxLo.D7gtoNGq.png",y="/anjian-workbuddy-bluebook-site/assets/012_publish-result_Qpz2bvBwTo.CwRG5daz.png",k="/anjian-workbuddy-bluebook-site/assets/013_anatomy-team_OI1Ubltu1o.Cf-1Sb2N.png",B="/anjian-workbuddy-bluebook-site/assets/014_anatomy-demo_PJuybCsQao.C8hzZ1I-.png",f="/anjian-workbuddy-bluebook-site/assets/015_anatomy-flow_CuFcbaM9Ao.C38u0uIQ.png",C="/anjian-workbuddy-bluebook-site/assets/016_audio-extract_EijVbt25mo.DyXCB_MA.png",x="/anjian-workbuddy-bluebook-site/assets/017_transcript-result_Zyc0bjAhTo.B390CAR4.png",w="/anjian-workbuddy-bluebook-site/assets/018_video-understand_VwxLb62b1o.CTpGVkMH.png",q="/anjian-workbuddy-bluebook-site/assets/019_clip-cut_HAWrbELZIo.J0Dd9-U_.png",H=JSON.parse('{"title":"第 19 章 一句话召唤 AI 视频团队","description":"在 WorkBuddy 里把短视频工作拆成两支 AI 专家团：一支负责自动生产视频，一支负责拆解爆款视频。 这两个团队并不是互相替代的关系。视频生成团队解决“今天怎么做一条出来”，爆款拆解团队解决“为什么别人那条能火，我能学到什么”。一个负责生产，一个负责学习，组合起来才有持续迭代的可能。","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 19 章 一句话召唤 AI 视频团队/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 19 章 一句话召唤 AI 视频团队/index.md","lastUpdated":1783659790000}'),P={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 19 章 一句话召唤 AI 视频团队/index.md"};function z(j,t,D,I,F,T){const a=e("MermaidDiagram");return s(),d("div",null,[t[0]||(t[0]=r('<h1 id="第-19-章-一句话召唤-ai-视频团队" tabindex="-1">第 19 章 一句话召唤 AI 视频团队 <a class="header-anchor" href="#第-19-章-一句话召唤-ai-视频团队" aria-label="Permalink to &quot;第 19 章 一句话召唤 AI 视频团队&quot;">​</a></h1><p>在 WorkBuddy 里把短视频工作拆成两支 AI 专家团：一支负责自动生产视频，一支负责拆解爆款视频。</p><p><img src="'+l+'" alt="" loading="lazy"></p><table tabindex="0"><thead><tr><th>团队</th><th>负责什么</th><th>适合什么任务</th></tr></thead><tbody><tr><td><strong>视频生成团队</strong></td><td>从主题出发，完成热点采集、选题筛选、脚本、分镜、配音、渲染、字幕和发布。</td><td>AI 周报、产品更新、知识科普、行业分析、产品评测。</td></tr><tr><td><strong>爆款视频拆解团队</strong></td><td>从视频链接出发，下载视频、提取音频、转写文案、分析镜头语言，生成拆解报告和仿拍建议。</td><td>学习爆款结构、复盘竞品视频、沉淀拍摄手册、给生成团队提供参考。</td></tr></tbody></table><p>这两个团队并不是互相替代的关系。视频生成团队解决“今天怎么做一条出来”，爆款拆解团队解决“为什么别人那条能火，我能学到什么”。一个负责生产，一个负责学习，组合起来才有持续迭代的可能。</p><p><img src="'+p+'" alt="" loading="lazy"></p><h2 id="如何召唤-从一句话开始-但不要停在一句话" tabindex="-1">如何召唤：从一句话开始，但不要停在一句话 <a class="header-anchor" href="#如何召唤-从一句话开始-但不要停在一句话" aria-label="Permalink to &quot;如何召唤：从一句话开始，但不要停在一句话&quot;">​</a></h2><p><img src="'+b+'" alt="" loading="lazy"></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>召唤视频生成团队，制作一条 46 秒 AI 周报短视频。</span></span></code></pre></div><h2 id="第一支团队-视频生成团队" tabindex="-1">第一支团队：视频生成团队 <a class="header-anchor" href="#第一支团队-视频生成团队" aria-label="Permalink to &quot;第一支团队：视频生成团队&quot;">​</a></h2><p>视频生成团队里有四个核心角色：视频生成团队主理人凌导、信息采集员灵阅、内容策划师灵枢、视频制作师灵映。它们不是四个换名字的聊天窗口，而是一条有上下游交接关系的视频生产线。</p><p><img src="'+h+'" alt="" loading="lazy"></p><table tabindex="0"><thead><tr><th>角色</th><th>定位</th><th>交付物</th></tr></thead><tbody><tr><td>凌导</td><td>主理人 / 团长</td><td>拆解任务、安排并行与串行流程、汇总产物、处理检查点。</td></tr><tr><td>灵阅</td><td>信息采集员</td><td>热点池、来源表、去重后的结构化摘要、选题候选。</td></tr><tr><td>灵枢</td><td>内容策划师</td><td>选题判断、脚本、分镜、旁白、转场、素材清单、BGM 和字幕节奏。</td></tr><tr><td>灵映</td><td>视频制作师</td><td>HTML 视频工程、配音、字幕对齐、转场动画、素材拼接、渲染成片。</td></tr></tbody></table><p>这才是多 Agent 的关键：不是角色越多越好，而是每个角色都有清晰输入和输出。信息采集员不直接写成片脚本，策划师不重新编造热点，制作师不重写事实，团长负责让流程不断档。</p><p><img src="'+_+'" alt="" loading="lazy"></p><h3 id="底层生产引擎-hyperframes" tabindex="-1">底层生产引擎：HyperFrames <a class="header-anchor" href="#底层生产引擎-hyperframes" aria-label="Permalink to &quot;底层生产引擎：HyperFrames&quot;">​</a></h3><p>文章提到，这条视频流水线基于 HyperFrames 搭建。它的核心思路是用 HTML 渲染视频，天然适合 Agent 生成结构化工程，再交给渲染工具输出 MP4。它还带有 CLI 工具链、TTS、字幕、去背景和视频组件模板。</p><p><img src="'+u+'" alt="" loading="lazy"></p><h3 id="生成流程一-信息采集员先让热点有来源" tabindex="-1">生成流程一：信息采集员先让热点有来源 <a class="header-anchor" href="#生成流程一-信息采集员先让热点有来源" aria-label="Permalink to &quot;生成流程一：信息采集员先让热点有来源&quot;">​</a></h3><p>做视频最耗时间的往往不是剪辑，而是“今天到底拍什么”。所以视频生成团队先让信息采集员灵阅抓 RSS、搜新闻、扫社媒、聚合 AI 热点，并去重输出结构化摘要。</p><p><img src="'+c+'" alt="" loading="lazy"></p><p>这个阶段的产物至少应该包含：标题、来源、发布时间、事件发生时间、原始链接、热度线索、为什么值得关注。热度只能帮助排序，不能替代事实核验。</p><h3 id="生成流程二-内容策划师把主题变成镜头" tabindex="-1">生成流程二：内容策划师把主题变成镜头 <a class="header-anchor" href="#生成流程二-内容策划师把主题变成镜头" aria-label="Permalink to &quot;生成流程二：内容策划师把主题变成镜头&quot;">​</a></h3><p>选题有了之后，真正费脑子的是“这条视频怎么讲”。内容策划师灵枢负责选题评估、脚本写作、分镜设计、旁白文案、镜头节奏，以及转场建议、素材清单、BGM 节奏、字幕停顿和情绪节点。</p><p><img src="'+m+'" alt="" loading="lazy"></p><p>这里建议设置第一次人工检查：开头 3 秒是否有钩子，46 秒是否塞入过多信息，旁白是否准确，画面是否真的支撑观点。脚本不过关时，不要进入配音和渲染。</p><h3 id="生成流程三-视频制作师把分镜变成成片" tabindex="-1">生成流程三：视频制作师把分镜变成成片 <a class="header-anchor" href="#生成流程三-视频制作师把分镜变成成片" aria-label="Permalink to &quot;生成流程三：视频制作师把分镜变成成片&quot;">​</a></h3><p>灵映会把确认后的脚本转成 HTML，再调用 HyperFrames 渲染 MP4。文章里提到，系统会自动完成 Azure TTS 配音、Whisper 字幕对齐、动画与转场生成、素材拼接、字幕叠加和视频渲染。</p><p><img src="'+E+'" alt="" loading="lazy"></p><p><img src="'+g+'" alt="" loading="lazy"></p><p>成片验收不要只看“能不能播放”。至少检查旁白与字幕是否一致、镜头时长是否匹配、文字是否遮挡主体、BGM 是否可用、素材是否有版权风险、画面是否适合目标平台安全区。</p><h3 id="生成流程四-发布可以自动化-但默认要人工确认" tabindex="-1">生成流程四：发布可以自动化，但默认要人工确认 <a class="header-anchor" href="#生成流程四-发布可以自动化-但默认要人工确认" aria-label="Permalink to &quot;生成流程四：发布可以自动化，但默认要人工确认&quot;">​</a></h3><p>发布 Agent 自动生成标题、自动打标签、自动上传封面，并通过云手机发布到抖音、视频号和 B 站。这是很强的自动化能力，但蓝皮书建议默认不要直接自动发布，除非账号、素材、标题和合规边界都已经过人工确认。</p><p><img src="'+A+'" alt="" loading="lazy"></p><p><img src="'+y+'" alt="" loading="lazy"></p><h2 id="第二支团队-爆款视频拆解团队" tabindex="-1">第二支团队：爆款视频拆解团队 <a class="header-anchor" href="#第二支团队-爆款视频拆解团队" aria-label="Permalink to &quot;第二支团队：爆款视频拆解团队&quot;">​</a></h2><p>光会生成还不够。</p><p>内容创作者真正需要的是理解“为什么别人能爆”，把一条爆款视频拆成可以参考的操作手册：提取视频、转录文案、分析景别运镜、剪辑节奏、色调风格，并给出仿拍建议。</p><p><img src="'+k+'" alt="" loading="lazy"></p><p><img src="'+B+'" alt="" loading="lazy"></p><table tabindex="0"><thead><tr><th>角色</th><th>职责</th><th>工具 / 技术</th></tr></thead><tbody><tr><td>阿爆</td><td>团长 / 拆解总控</td><td>任务调度、流程编排、结果汇总。</td></tr><tr><td>小凯</td><td>音频处理与转录</td><td>ffmpeg、ASR，把视频音频转成完整口播文案。</td></tr><tr><td>小淼</td><td>视频理解与镜头裁切</td><td>视频理解 API、ffmpeg，分析镜头语言并裁切片段。</td></tr></tbody></table><h3 id="拆解流程一-视频下载要有降级策略" tabindex="-1">拆解流程一：视频下载要有降级策略 <a class="header-anchor" href="#拆解流程一-视频下载要有降级策略" aria-label="Permalink to &quot;拆解流程一：视频下载要有降级策略&quot;">​</a></h3><p>爆款拆解的第一步是拿到视频。文章里专门提到，最复杂的是视频下载，所以设计了一套三层降级策略：官方 API、Playwright、yt-dlp。只要有一层成功，流程就继续。</p><p><img src="'+f+'" alt="" loading="lazy"></p><p>这里必须加上边界：视频下载和分析要遵守平台条款、版权授权和合理使用范围。拆解的目的应该是学习结构和方法，不是搬运原视频。</p><h3 id="拆解流程二-音频提取与文案转写" tabindex="-1">拆解流程二：音频提取与文案转写 <a class="header-anchor" href="#拆解流程二-音频提取与文案转写" aria-label="Permalink to &quot;拆解流程二：音频提取与文案转写&quot;">​</a></h3><p>视频下载完成后，小凯用 ffmpeg 提取音频，把 video.mp4 转成 audio.mp3，再调用语音识别 API 自动转录完整口播文案。以前一句句听、一句句敲的工作，现在可以被稳定自动化。</p><p><img src="'+C+'" alt="" loading="lazy"></p><p><img src="'+x+'" alt="" loading="lazy"></p><h3 id="拆解流程三-视频理解与镜头语言分析" tabindex="-1">拆解流程三：视频理解与镜头语言分析 <a class="header-anchor" href="#拆解流程三-视频理解与镜头语言分析" aria-label="Permalink to &quot;拆解流程三：视频理解与镜头语言分析&quot;">​</a></h3><p>接下来是最有意思的一步：视频理解。小淼会分析整条视频的景别、运镜、转场、剪辑节奏、色调、镜头时长。很多看起来“有感觉”的爆款视频，背后其实有稳定的镜头规律。</p><p><img src="'+w+'" alt="" loading="lazy"></p><p><img src="'+q+'" alt="" loading="lazy"></p><h2 id="两支团队如何形成闭环" tabindex="-1">两支团队如何形成闭环 <a class="header-anchor" href="#两支团队如何形成闭环" aria-label="Permalink to &quot;两支团队如何形成闭环&quot;">​</a></h2><p>两个专家团可以合作。先用爆款拆解团队学习镜头语言和节奏，再让视频生成团队生产新视频，发布之后继续分析数据，再反过来优化下一版内容。</p>',55)),i(a,{graph:"flowchart%20LR%0A%20%20%20%20A%5B%E7%88%86%E6%AC%BE%E8%A7%86%E9%A2%91%E9%93%BE%E6%8E%A5%5D%20--%3E%20B%5B%E6%8B%86%E8%A7%A3%E5%9B%A2%E9%98%9F%EF%BC%9A%E8%BD%AC%E5%86%99%E3%80%81%E9%95%9C%E5%A4%B4%E3%80%81%E8%8A%82%E5%A5%8F%E3%80%81%E4%BB%BF%E6%8B%8D%E5%BB%BA%E8%AE%AE%5D%0A%20%20%20%20B%20--%3E%20C%5B%E5%BD%A2%E6%88%90%E6%8B%8D%E6%91%84%E6%89%8B%E5%86%8C%E5%92%8C%E5%86%85%E5%AE%B9%E8%A7%84%E5%BE%8B%5D%0A%20%20%20%20C%20--%3E%20D%5B%E7%94%9F%E6%88%90%E5%9B%A2%E9%98%9F%EF%BC%9A%E7%83%AD%E7%82%B9%E3%80%81%E8%84%9A%E6%9C%AC%E3%80%81%E5%88%86%E9%95%9C%E3%80%81%E6%B8%B2%E6%9F%93%5D%0A%20%20%20%20D%20--%3E%20E%5B%E4%BA%BA%E5%B7%A5%E9%AA%8C%E6%94%B6%E4%B8%8E%E5%8F%91%E5%B8%83%5D%0A%20%20%20%20E%20--%3E%20F%5B%E6%95%B0%E6%8D%AE%E5%A4%8D%E7%9B%98%5D%0A%20%20%20%20F%20--%3E%20B%0A"}),t[1]||(t[1]=n("p",null,"这就是专家团比单个工具更有意义的地方。它不只是帮你做一条视频，而是让“学习、生产、发布、复盘”变成一个可以重复运转的系统。",-1))])}const M=o(P,[["render",z]]);export{H as __pageData,M as default};
